use rayon::prelude::*;

#[test]
fn test_par_iter_sum() {
    let sum: i64 = (1..=100).into_par_iter().sum();
    assert_eq!(sum, 5050);
}

#[test]
fn test_par_iter_map() {
    let squares: Vec<i64> = (1..=5).into_par_iter().map(|x| x * x).collect();
    assert_eq!(squares, vec![1, 4, 9, 16, 25]);
}

#[test]
fn test_par_iter_filter() {
    let evens: Vec<i64> = (1..=10).into_par_iter().filter(|x| x % 2 == 0).collect();
    assert_eq!(evens, vec![2, 4, 6, 8, 10]);
}
